from pathlib import Path
import re

p = Path(r'D:\Projects\bazi-portal\names.html')
s = p.read_text(encoding='utf-8', errors='ignore')
start = s.find('const patternDirection=')
if start == -1:
    raise SystemExit('const patternDirection not found')
new_tail = r'''const patternDirection={"火格": "偏木", "土格": "偏木/水", "木火格": "偏木/土", "水火格": "偏木", "火土格": "偏木", "金火格": "偏水/木"}; const patternBg={"火格": "linear-gradient(135deg, rgba(255,123,114,.22), rgba(255,179,107,.10))", "土格": "linear-gradient(135deg, rgba(199,163,107,.20), rgba(237,211,160,.10))", "木火格": "linear-gradient(135deg, rgba(111,211,157,.18), rgba(255,171,110,.10))", "水火格": "linear-gradient(135deg, rgba(118,184,255,.18), rgba(255,151,176,.10))", "火土格": "linear-gradient(135deg, rgba(255,149,117,.18), rgba(197,154,99,.10))", "金火格": "linear-gradient(135deg, rgba(217,227,243,.18), rgba(255,171,121,.10))"}; const patternStyle={"火格": "color:#ff9db3;text-shadow:0 2px 14px rgba(255,157,179,.16)", "土格": "color:#d9b375;text-shadow:0 2px 12px rgba(217,179,117,.14)", "木火格": "background:linear-gradient(135deg,#79d99e 0%,#90d88a 40%,#ff8e7a 100%);-webkit-background-clip:text;background-clip:text;color:transparent;text-shadow:none", "水火格": "background:linear-gradient(135deg,#79b7ff 0%,#8eaaff 45%,#ff8b9f 100%);-webkit-background-clip:text;background-clip:text;color:transparent;text-shadow:none", "火土格": "background:linear-gradient(135deg,#e25a4b,#e7b066);-webkit-background-clip:text;background-clip:text;color:transparent;text-shadow:none", "金火格": "background:linear-gradient(135deg,#eef4ff,#ffb37f);-webkit-background-clip:text;background-clip:text;color:transparent;text-shadow:none"}; let currentGender='男'; const patterns=['火格','土格','木火格','水火格','火土格','金火格']; const container=document.getElementById('patterns'); const maleBtn=document.getElementById('maleBtn'); const femaleBtn=document.getElementById('femaleBtn'); const heroSection=document.getElementById('heroSection'); const body=document.body; function render(){ container.innerHTML = patterns.map(p=>{ const list=(currentGender==='男'?topData[p].boys:topData[p].girls); return `<article class="card pattern-card" id="${p}" style="background-image:${patternBg[p]}"><div class="pattern-head"><div class="pattern-left"><span class="badge">${patternDirection[p]}</span></div><div class="pattern-title" style="${patternStyle[p]}">${p}</div><div class="pattern-right"><span class="badge">10个名字</span></div></div>${list.map(r=>`<div class="name-line"><div class="subline"><div><div class="name-calligraphy" style="${patternStyle[p]}">${r.name}</div><span class="small">${r.pinyin}</span></div><div class="score">${r.score} 分</div></div><div class="note"><b>五行：</b>${r.wuxing}<br><b class="meaning">组合意思：</b><span class="meaning">${r.meaning}</span><br><b>出处：</b>${r.source}<br><span class="reason"><b>评分理由：</b><strong>评分 ${r.score}</strong>，${r.reason.replace(/^评分\s*\d+分/,'')}</span></div></div>`).join('')}</article>`; }).join(''); } function syncGenderButtons(){ const isMale=currentGender==='男'; maleBtn.classList.toggle('active',isMale); femaleBtn.classList.toggle('active',!isMale); } function updateStickyState(){ if(heroSection) heroSection.classList.toggle('compact', window.scrollY > 18); } maleBtn.onclick=()=>{currentGender='男'; body.className='names-page theme-male'; syncGenderButtons(); render();}; femaleBtn.onclick=()=>{currentGender='女'; body.className='names-page theme-female'; syncGenderButtons(); render();}; body.className='names-page theme-male'; syncGenderButtons(); render(); window.addEventListener('scroll', updateStickyState, {passive:true}); window.addEventListener('resize', updateStickyState); updateStickyState();</script></body></html>'''
s = s[:start] + new_tail
p.write_text(s, encoding='utf-8')
print('restored detail section and kept top layout')
